using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            environment = "production",
            maxRetries = 3,
            timeoutSeconds = 30,
            featureFlags = new
            {
                darkMode = true,
                betaFeatures = false
            }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up a configuration value by key name.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'maxRetries', 'environment')")] string key)
    {
        var values = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase)
        {
            ["environment"] = "production",
            ["maxRetries"] = "3",
            ["timeoutSeconds"] = "30",
            ["darkMode"] = "true",
            ["betaFeatures"] = "false"
        };

        return values.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Unknown configuration key: '{key}'";
    }

    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join(", ", "environment", "maxRetries", "timeoutSeconds", "darkMode", "betaFeatures");
    }
}

